import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Row, Col, Card, Table, Button, Space, Typography, 
  Tag, Progress, Breadcrumb, App, Input, Modal, Form, 
  Select, DatePicker, message, Divider, Tooltip, Empty, Flex
} from "antd";
import { 
  InfoCircleOutlined, PlusOutlined, ExportOutlined, 
  SearchOutlined, TeamOutlined, CalendarOutlined, 
  SettingOutlined, DeleteOutlined, EditOutlined,
  FolderOpenOutlined, SyncOutlined
} from "@ant-design/icons";
import dayjs from "dayjs";

const { useToken } = theme;
const { Title, Text } = Typography;
const { RangePicker } = DatePicker;

const mockProjects = [
  { key: "1", id: "PRJ-2026-001", name: "Autonomous Driving - Urban Roads", status: "In Progress", pm: "Kim PM", progress: 65, goal: 10000, current: 6500, start: "2026-01-01", end: "2026-06-30", taskCount: 4 },
  { key: "2", id: "PRJ-2026-002", name: "CCTV Safety Monitoring", status: "Pending", pm: "Lee PM", progress: 0, goal: 5000, current: 0, start: "2026-04-01", end: "2026-09-30", taskCount: 2 },
  { key: "3", id: "PRJ-2026-003", name: "Medical Imaging Analysis", status: "In Progress", pm: "Park PM", progress: 88, goal: 2000, current: 1760, start: "2026-02-15", end: "2026-05-15", taskCount: 8 },
];

export default function ProjectManagement() {
  const { token } = useToken();
  const { t } = useTranslation(["project", "common"]);
  const [isPrjModalOpen, setIsPrjModalOpen] = useState(false);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [isPathModalOpen, setIsPathModalOpen] = useState(false);
  const [editingPrj, setEditingPrj] = useState<any>(null);
  const [form] = Form.useForm();

  const handlePrjEdit = (record: any) => {
    setEditingPrj(record);
    form.setFieldsValue({
      name: record.name,
      pm: record.pm,
      goal: record.goal,
      period: [dayjs(record.start), dayjs(record.end)]
    });
    setIsPrjModalOpen(true);
  };

  const handlePrjDelete = (record: any) => {
    Modal.confirm({
      title: t("msg.deleteConfirm", { name: record.name }),
      okText: t("delete", { ns: "common" }),
      okType: "danger",
      cancelText: t("cancel", { ns: "common" }),
      onOk: () => message.success(t("msg.deleted"))
    });
  };

  const projectColumns = [
    { title: t("modal.prjNm"), dataIndex: "name", key: "name", render: (text: string) => <Text strong>{text}</Text> },
    { title: t("columns.pm"), dataIndex: "pm", key: "pm", align: "center" as const },
    { 
      title: t("progress"), dataIndex: "progress", key: "progress", width: 200,
      render: (v: number) => <Progress percent={v} size="small" strokeColor={token.colorPrimary} />
    },
    { title: t("columns.period"), key: "period", render: (_:any, r:any) => <Text style={{ fontSize: 11 }}>{r.start} ~ {r.end}</Text> },
    {
      title: t("columns.view"), key: "action", align: "center" as const,
      render: (_:any, record:any) => (
        <Space>
          <Tooltip title={t("edit", { ns: "common" })}><Button type="text" size="small" icon={<EditOutlined />} onClick={() => handlePrjEdit(record)} /></Tooltip>
          <Tooltip title={t("delete", { ns: "common" })}><Button type="text" size="small" danger icon={<DeleteOutlined />} onClick={() => handlePrjDelete(record)} /></Tooltip>
        </Space>
      )
    }
  ];

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
        <Flex vertical gap={2}>
          <Title level={3} style={{ margin: 0 }}>{t("title")}</Title>
          <Text type="secondary">{t("subtitle")}</Text>
        </Flex>
        <Space>
          <Button icon={<ExportOutlined />} onClick={() => message.info(t("msg.exportDone"))}>{t("export")}</Button>
          <Button type="primary" icon={<PlusOutlined />} onClick={() => { setEditingPrj(null); form.resetFields(); setIsPrjModalOpen(true); }}>{t("createBtn")}</Button>
        </Space>
      </div>

      <Row gutter={[16, 16]}>
        <Col span={24}>
          <Card 
            title={<Space><SearchOutlined /> <Text strong>{t("listTitle")}</Text></Space>} 
            variant="borderless"
            style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }}
          >
            <Table 
              dataSource={mockProjects} 
              columns={projectColumns as any} 
              pagination={{ pageSize: 5 }}
              locale={{ emptyText: t("noObjects", { ns: "common" }) }}
            />
          </Card>
        </Col>

        <Col span={12}>
          <Card 
            title={<Space><CalendarOutlined /> <Text strong>{t("taskTitle")}</Text></Space>} 
            extra={<Button size="small" type="dashed" icon={<PlusOutlined />} onClick={() => setIsTaskModalOpen(true)}>{t("addTaskBtn")}</Button>}
            variant="borderless"
            style={{ borderRadius: 12, height: 400, boxShadow: token.boxShadowTertiary }}
          >
             <Empty description={t("select", { ns: "common" })} style={{ marginTop: 60 }} />
          </Card>
        </Col>

        <Col span={12}>
          <Card 
            title={<Space><SettingOutlined /> <Text strong>{t("jobTitle")}</Text></Space>} 
            extra={<Button size="small" type="link" icon={<FolderOpenOutlined />} onClick={() => setIsPathModalOpen(true)}>{t("modal.pathSelect")}</Button>}
            variant="borderless"
            style={{ borderRadius: 12, height: 400, boxShadow: token.boxShadowTertiary }}
          >
             <Empty description={t("select", { ns: "common" })} style={{ marginTop: 60 }} />
          </Card>
        </Col>
      </Row>

      <Modal 
        title={editingPrj ? t("modal.prjEdit") : t("modal.prjAdd")} 
        open={isPrjModalOpen} 
        onOk={() => setIsPrjModalOpen(false)} 
        onCancel={() => setIsPrjModalOpen(false)}
        okText={editingPrj ? t("save", { ns: "common" }) : t("add", { ns: "common" })}
        cancelText={t("cancel", { ns: "common" })}
        destroyOnHidden
      >
        <Form form={form} layout="vertical" style={{ marginTop: 24 }}>
          <Form.Item name="name" label={t("modal.prjNm")} rules={[{ required: true }]}><Input /></Form.Item>
          <Form.Item name="pm" label={t("modal.pmNm")} rules={[{ required: true }]}><Input /></Form.Item>
          <Row gutter={16}>
            <Col span={12}><Form.Item name="goal" label={t("modal.goal")} initialValue={1000}><Input type="number" suffix={t("unit", { ns: "common" })} /></Form.Item></Col>
            <Col span={12}><Form.Item name="format" label={t("modal.format")} initialValue="COCO"><Select><Select.Option value="COCO">COCO JSON</Select.Option><Select.Option value="YOLO">YOLO TXT</Select.Option></Select></Form.Item></Col>
          </Row>
          <Form.Item name="period" label={t("columns.period")}><RangePicker style={{ width: "100%" }} /></Form.Item>
        </Form>
      </Modal>

      <Modal title={t("modal.taskAdd")} open={isTaskModalOpen} onCancel={() => setIsTaskModalOpen(false)} footer={null} centered destroyOnHidden>
        <Form form={form} layout="vertical" style={{ marginTop: 16 }}>
          <Form.Item label={t("modal.taskNm")}><Input placeholder="Urban Highway A..." /></Form.Item>
          <Form.Item label={t("modal.taskPath")}><Input placeholder="/data/raw/urban_01" /></Form.Item>
          <Button type="primary" block onClick={() => { message.success(t("msg.saved")); setIsTaskModalOpen(false); }}>{t("add", { ns: "common" })}</Button>
        </Form>
      </Modal>

      <Modal title={t("modal.pathSelect")} open={isPathModalOpen} onCancel={() => setIsPathModalOpen(false)} width={600} centered destroyOnHidden>
         <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between" }}>
            <Text type="secondary">{t("modal.imgPath")}: /nas/ai_training/safety_2026</Text>
            <Button size="small" icon={<SyncOutlined />}>{t("modal.sync")}</Button>
         </div>
         <Table 
            size="small" 
            pagination={false}
            dataSource={[
              { key: 'd1', name: 'cctv_0411', count: 1200, camera: 'CAM-A' },
              { key: 'd2', name: 'cctv_0412', count: 850, camera: 'CAM-B' }
            ]}
            columns={[
              { title: t("modal.dirName"), dataIndex: "name" },
              { title: t("modal.imgCountInDir"), dataIndex: "count", align: "right" as const },
              { title: t("modal.camera"), dataIndex: "camera" },
              { title: t("common.select", { ns: "common" }), key: "sel", render: () => <Button size="small">{t("modal.apply")}</Button> }
            ]}
         />
      </Modal>
    </div>
  );
}
